with detail = 1 {
    with link = "line.dk.SBF" {
        track(:first :pax :removed, path("d1.dk.sbf")[:sve.yf, :kat.ys]);
    }

    with link = "line.dk.SBS" {
        let ss = path("d1.dk.sbs");

        with railway = :first :pax {
            track(ss[:ska.ys, :sil.yl]);
            track(ss[:sil.yl, :sil.yh]);
            track(ss[:sil.yh, :sil.yr]);
            track(ss[:sil.yr, :fun.yb]);
            track(ss[:fun.yb, :her.ys]);
            track(ss[:her.yh, :tro.yk]);
            track(ss[:tro.yk, :ske.ys]);
        }
    }

    with link = "line.dk.SHT" {
        track(:first :double :cat:ac25 :pax,
                path("d1.dk.sht")[:sno, :tau.ys]
        );
    }

    with link = "line.dk.SHT" {
        track(:first :pax :removed, path("d1.dk.sls")[:skr.ys, :spo]);
    }

    with link = "line.dk.SMS" {
        let ss = path("d1.dk.sms");

        track(:first :double :cat:dc15 :pax, ss[:ryp.yf, :far]);
        track(:first :pax :removed, ss[:far, :sla]);
    }

    with link = "line.dk.SNN" {
        let sn = path("d1.dk.snn");

        with railway = :first :pax :removed {
            track(sn[:stu, :nyk.ys]);
            track(sn[:nyk.yg, :nys]);
        }
    }

    with link = "line.dk.SNB" {
        track(:first :pax :removed, path("d1.dk.snb")[:sve, :nyb.ys]);
    }

    with link = "line.dk.SNV" {
        let sn = path("d1.dk.snv");

        with railway = :first :pax :removed {
            track(sn[:sla.yv, :dal.ys]);
            track(sn[:dal.ys, :nas.ys]);
        }
    }

    with link = "line.dk.SRV" {
        track(:first :removed, path("d1.dk.srv")[:sor.yv, :ved.ys]);
    }

    with link = "line.dk.SSK" {
        track(:first :double :pax :removed,
                path("d1.dk.ssk")[:sve.yk, :kor]
        );
    }

    with link = "line.dk.STS" {
        let st = path("d1.dk.sts");

        with railway = :first :pax {
            track(st[:str, :thi.yf]);
            track(st[:thi.yf, :thi]);
        }
    }

    with link = "line.dk.SVB" {
        let sv = path("d1.dk.svb");

        track(:first :pax :closed, sv[:ske.yv, :her]);
        track(:first :pax :removed, sv[:her, :vid]);
    }

    with link = "line.dk.SVL" {
        let sv = path("d1.dk.svl");

        track(:first :pax, sv[:sla.yv, :hon.yt]);
        track(:first :nopax, sv[:hon.yt, :gor]);
        track(:first :pax :removed, sv[:gor, :var.ys]);
    }
}

